	r.HandleFunc(options.BaseURL+"/api/chart/material", wrapper.CheckMaterialChart).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/chart/storage", wrapper.GetStorageChart).Methods("GET")

	r.HandleFunc(options.BaseURL+"/api/chart/storage", wrapper.CheckStorageChart).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/color/{id}", wrapper.KillColor).Methods("DELETE")

	r.HandleFunc(options.BaseURL+"/api/color/{id}", wrapper.CheckColor).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/color/{id}", wrapper.UpdateColor).Methods("PATCH")

	r.HandleFunc(options.BaseURL+"/api/colors", wrapper.FindColors).Methods("GET")

	r.HandleFunc(options.BaseURL+"/api/colors", wrapper.CheckColors).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/colors", wrapper.CreateColor).Methods("POST")

	r.HandleFunc(options.BaseURL+"/api/health/check", wrapper.HealthCheck).Methods("GET")

	r.HandleFunc(options.BaseURL+"/api/location/{id}", wrapper.KillLocation).Methods("DELETE")

	r.HandleFunc(options.BaseURL+"/api/location/{id}", wrapper.CheckLocation).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/location/{id}", wrapper.UpdateLocation).Methods("PATCH")

	r.HandleFunc(options.BaseURL+"/api/locations", wrapper.FindLocations).Methods("GET")

	r.HandleFunc(options.BaseURL+"/api/locations", wrapper.CheckLocations).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/locations", wrapper.CreateLocation).Methods("POST")

	r.HandleFunc(options.BaseURL+"/api/material/{id}", wrapper.KillMaterial).Methods("DELETE")

	r.HandleFunc(options.BaseURL+"/api/material/{id}", wrapper.CheckMaterial).Methods("OPTIONS")

	r.HandleFunc(options.BaseURL+"/api/material/{id}", wrapper.UpdateMaterial).Methods("PATCH")

